对每个单号：① 从下标1开始检查 s[i]==s[i-1] 判重；② 统计 isalpha(c) 和 isdigit(c) 的个数；③ 两个计数均为偶数则 ans++。三条件缺一不可。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, ans = 0;
    cin >> n;
    while (n--) {
        string s;
        cin >> s;
        bool ok = true;
        for (int i = 1; i < 10; i++)
            if (s[i] == s[i-1]) { ok = false; break; }
        int letters = 0, digits = 0;
        for (char c : s) {
            if (isalpha(c)) letters++;
            else digits++;
        }
        if (letters % 2 != 0 || digits % 2 != 0) ok = false;
        if (ok) ans++;
    }
    cout << ans << endl;
    return 0;
}
```

枚举 i<j 无序对，同时满足 |d[i]-d[j]|≤k 才用 r[i]+r[j] 更新最大值。ans 初始为 -1，全程未更新则输出 -1。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, k, d[5005], r[5005];
    cin >> n >> k;
    for (int i = 0; i < n; i++) cin >> d[i] >> r[i];
    int ans = -1;
    for (int i = 0; i < n; i++)
        for (int j = i + 1; j < n; j++)
            if (abs(d[i] - d[j]) <= k)
                ans = max(ans, r[i] + r[j]);
    cout << ans << endl;
    return 0;
}
```

枚举 2×k 子矩阵左上角 (i,j)，i 从 0 到 n-3，j 从 0 到 m-k，用二重循环累加 2k 个格子之和取最小值。ans 初始化为 1e9。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, m, k, a[55][55];
    cin >> n >> m >> k;
    for (int i = 0; i < n; i++)
        for (int j = 0; j < m; j++) cin >> a[i][j];
    int ans = 1e9;
    for (int i = 0; i <= n - 2; i++)
        for (int j = 0; j <= m - k; j++) {
            int sum = 0;
            for (int di = 0; di < 2; di++)
                for (int dj = 0; dj < k; dj++)
                    sum += a[i + di][j + dj];
            ans = min(ans, sum);
        }
    cout << ans << endl;
    return 0;
}
```

定义结构体存 name, group, score。cmp 先比 group 升序（1<2<3），同组时短跑长跑 score 升序、田赛 score 降序，成绩相同按 name 升序。排序后输出 name。

```cpp
#include <bits/stdc++.h>
using namespace std;
struct Stu {
    string name;
    int group;
    double score;
};
bool cmp(Stu a, Stu b) {
    if (a.group != b.group) return a.group < b.group;
    if (a.group <= 2) { // 短跑、长跑：升序
        if (a.score != b.score) return a.score < b.score;
    } else { // 田赛：降序
        if (a.score != b.score) return a.score > b.score;
    }
    return a.name < b.name;
}
int main() {
    int n;
    cin >> n;
    vector<Stu> v(n);
    for (int i = 0; i < n; i++)
        cin >> v[i].name >> v[i].group >> v[i].score;
    sort(v.begin(), v.end(), cmp);
    for (int i = 0; i < n; i++) cout << v[i].name << endl;
    return 0;
}
```
